func processQueueJob(
	backend Backend,
	sourceURI string,
	namespace string,
	embedModel string,
	batchSize int,
	runNER bool,
	spaCyModel string,
) error {
	loader := NewDocumentLoader()
	chunks, err := loader.Load(sourceURI)
	if err != nil {
		return fmt.Errorf("failed to load %q: %w", sourceURI, err)
	}

	if len(chunks) == 0 {
		return nil
	}

	var contents []string
	for _, c := range chunks {
		contents = append(contents, c.Content)
	}
	joinedContent := strings.Join(contents, "\n")
	hash := sha256.Sum256([]byte(joinedContent))
	contentHash := fmt.Sprintf("%x", hash)[:32]

	emb, err := embedTexts(contents, embedModel, batchSize)
	if err != nil {
		return fmt.Errorf("embed failed: %w", err)
	}
	if err := backend.AddChunks(chunks, emb, namespace); err != nil {
		return fmt.Errorf("add_chunks: %w", err)
	}
	if err := backend.RegisterDocument(
		chunks[0].DocumentName,
		contentHash,
		sourceURI,
		len(chunks),
	); err != nil {
		return fmt.Errorf("register_document: %w", err)
	}

	if runNER {
		if err := buildNER(backend, spaCyModel); err != nil {
			return fmt.Errorf("ner: %w", err)
		}
	}
	return nil
}

type WorkerOptions struct {
	EmbedModel  string
	BatchSize   int
	RunNER      bool
	SpaCyModel  string
	IdleSleep   time.Duration
}

func RunWorker(queueDSN, backendDSN string, opts WorkerOptions) error {
	if opts.EmbedModel == "" {
		opts.EmbedModel = "BAAI/bge-large-en-v1.5"
	}
	if opts.BatchSize == 0 {
		opts.BatchSize = 256
	}
	if opts.SpaCyModel == "" {
		opts.SpaCyModel = "en_core_web_sm"
	}
	if opts.IdleSleep == 0 {
		opts.IdleSleep = 2 * time.Second
	}

	hostname, err := os.Hostname()
	if err != nil {
		return fmt.Errorf("hostname: %w", err)
	}
	workerID := fmt.Sprintf("%s:%s", hostname, randomHex(8))

	backend, err := NewPgVectorBackend(backendDSN)
	if err != nil {
		return fmt.Errorf("backend: %w", err)
	}

	for {
		paused, err := queryControl(queueDSN, "workers_paused")
		if err != nil {
			return fmt.Errorf("query_control: %w", err)
		}
		if paused == "1" {
			time.Sleep(opts.IdleSleep)
			continue
		}

		job, err := claimNextJob(queueDSN, workerID)
		if err != nil {
			return fmt.Errorf("claim_job: %w", err)
		}
		if job == nil {
			time.Sleep(opts.IdleSleep)
			continue
		}

		procErr := processQueueJob(backend, job.SourceURI, job.Namespace,
			opts.EmbedModel, opts.BatchSize, opts.RunNER, opts.SpaCyModel)
		if procErr != nil {
			log.Printf("job %s failed: %v", job.ID, procErr)
			if err := markJob(queueDSN, job.ID, "failed"); err != nil {
				return fmt.Errorf("mark failed: %w", err)
			}
		} else {
			if err := markJob(queueDSN, job.ID, "done"); err != nil {
				return fmt.Errorf("mark done: %w", err)
			}
		}
	}
}

type CoordinatorOptions struct {
	GraphInterval         int
	EmbedModel            string
	SpaCyModel            string
	CommunityAlpha        float64
	CommunitySimThreshold float64
	LeaseTimeoutMinutes   int
	PollSleep             time.Duration
}

func RunCoordinator(queueDSN, backendDSN string, opts CoordinatorOptions) error {
	if opts.GraphInterval == 0 {
		opts.GraphInterval = 300
	}
	if opts.EmbedModel == "" {
		opts.EmbedModel = "BAAI/bge-large-en-v1.5"
	}
	if opts.PollSleep == 0 {
		opts.PollSleep = 5 * time.Second
	}

	state := "DISPATCHING"
	var lastGraphBuild time.Time

	for {
		now := time.Now()

		if state == "DISPATCHING" {
			if err := requeueStaleLeases(queueDSN, opts.LeaseTimeoutMinutes); err != nil {
				return fmt.Errorf("requeue_stale: %w", err)
			}
			pending, err := queuePendingCount(queueDSN)
			if err != nil {
				return fmt.Errorf("pending_count: %w", err)
			}
			queueEmpty := pending == 0
			intervalElapsed := now.Sub(lastGraphBuild) >= time.Duration(opts.GraphInterval)*time.Second
			if queueEmpty || intervalElapsed {
				state = "DRAINING"
			}
		} else if state == "DRAINING" {
			processing, err := queueProcessingCount(queueDSN)
			if err != nil {
				return fmt.Errorf("processing_count: %w", err)
			}
			if processing == 0 {
				state = "BUILDING"
			}
		} else if state == "BUILDING" {
			if err := setControl(queueDSN, "workers_paused", "1"); err != nil {
				return fmt.Errorf("set_control pause: %w", err)
			}
			buildErr := runGraphBuild(backendDSN, opts.EmbedModel, opts.CommunityAlpha, opts.CommunitySimThreshold)
			if err := setControl(queueDSN, "workers_paused", "0"); err != nil {
				return fmt.Errorf("set_control unpause: %w", err)
			}
			if buildErr != nil {
				log.Printf("graph build failed: %v", buildErr)
			}
			lastGraphBuild = time.Now()
			state = "DISPATCHING"
		}

		time.Sleep(opts.PollSleep)
	}
}

func requeueStaleLeases(dsn string, timeoutMinutes int) error {
	if timeoutMinutes == 0 {
		timeoutMinutes = 10
	}
	conn, err := pgConnect(dsn)
	if err != nil {
		return fmt.Errorf("pg_connect: %w", err)
	}
	defer conn.Close()

	query := fmt.Sprintf(
		"UPDATE ingest_queue SET status = 'pending', worker_id = NULL, leased_at = NULL "+
			"WHERE status = 'processing' AND leased_at < now() - interval '%d minutes'",
		timeoutMinutes,
	)
	res, err := conn.Exec(query)
	if err != nil {
		return fmt.Errorf("requeue exec: %w", err)
	}
	if err := conn.Commit(); err != nil {
		return fmt.Errorf("commit: %w", err)
	}

	count, err := res.RowsAffected()
	if err != nil {
		return fmt.Errorf("rows_affected: %w", err)
	}
	if count > 0 {
		log.Printf("requeued %d stale lease(s)", count)
	}
	return nil
}

func runGraphBuild(backendDSN, embedModel string, alpha, simThreshold float64) error {
	pg, err := NewPgVectorBackend(backendDSN)
	if err != nil {
		return fmt.Errorf("pg_connect: %w", err)
	}
	defer pg.Close()

	nsRows, err := pg.Conn.Query("SELECT DISTINCT namespace FROM embeddings WHERE namespace IS NOT NULL")
	if err != nil {
		return fmt.Errorf("query namespaces: %w", err)
	}
	var namespaces []string
	for nsRows.Next() {
		var ns string
		if err := nsRows.Scan(&ns); err != nil {
			return fmt.Errorf("scan namespace: %w", err)
		}
		namespaces = append(namespaces, ns)
	}
	nsRows.Close()

	if len(namespaces) == 0 {
		return nil
	}

	for _, ns := range namespaces {
		chunkRows, err := pg.Conn.Query(
			"SELECT chunk_id, document_name, content FROM embeddings WHERE namespace = $1", ns)
		if err != nil {
			return fmt.Errorf("query chunks for %s: %w", ns, err)
		}
		var tmpChunks []DocumentChunk
		for chunkRows.Next() {
			var chunkID, docName, content string
			if err := chunkRows.Scan(&chunkID, &docName, &content); err != nil {
				chunkRows.Close()
				return fmt.Errorf("scan chunk row: %w", err)
			}
			tmpChunks = append(tmpChunks, DocumentChunk{DocumentName: docName, Content: content})
		}
		chunkRows.Close()

		if len(tmpChunks) == 0 {
			continue
		}

		n, err := buildCommunity(ns, embedModel, alpha, simThreshold, true)
		if err != nil {
			return fmt.Errorf("build_community %s: %w", ns, err)
		}
		log.Printf("namespace %s: %d communities built", ns, n)
	}
	return nil
}

type EmbedConfig struct {
	Model     string
	BatchSize int
}

func embedChunks(chunks []DocumentChunk, cfg EmbedConfig) ([][]float32, error) {
	if cfg.Model == "" {
		cfg.Model = "BAAI/bge-large-en-v1.5"
	}
	if cfg.BatchSize == 0 {
		cfg.BatchSize = 256
	}

	var texts []string
	for _, c := range chunks {
		texts = append(texts, c.Content)
	}

	model, err := LoadSentenceTransformer(cfg.Model)
	if err != nil {
		return nil, fmt.Errorf("load model: %w", err)
	}

	var vecs [][]float32
	for i := 0; i < len(texts); i += cfg.BatchSize {
		end := i + cfg.BatchSize
		if end > len(texts) {
			end = len(texts)
		}
		batch := texts[i:end]
		v, err := model.Encode(batch, false, true)
		if err != nil {
			return nil, fmt.Errorf("encode batch at %d: %w", i, err)
		}
		vecs = append(vecs, v...)
		done := end
		if (i/cfg.BatchSize)%10 == 0 {
			fmt.Printf("  embedded %d/%d\n", done, len(texts))
		}
	}
	return vecs, nil
}

