func ingestGlob(loader *DocumentLoader, src map[string]string) ([]DocumentChunk, error) {
	basePath := src["path"]
	pattern := src["pattern"]
	if pattern == "" {
		pattern = "*"
	}
	prefix := src["name_prefix"]
	docType := src["doc_type"]

	matches, err := filepath.Glob(filepath.Join(basePath, pattern))
	if err != nil {
		return nil, fmt.Errorf("glob %q: %w", filepath.Join(basePath, pattern), err)
	}
	sort.Strings(matches)

	var chunks []DocumentChunk
	for _, p := range matches {
		base := filepath.Base(p)
		if strings.HasPrefix(base, ".") {
			continue
		}
		stem := strings.TrimSuffix(base, filepath.Ext(base))
		name := prefix + stem
		if docType != "" {
			data, err := os.ReadFile(p)
			if err != nil {
				return nil, fmt.Errorf("read %q: %w", p, err)
			}
			c, err := loader.LoadBytes(data, name, docType)
			if err != nil {
				return nil, fmt.Errorf("load_bytes %q: %w", p, err)
			}
			chunks = append(chunks, c...)
		} else {
			c, err := loader.Load(p, name)
			if err != nil {
				return nil, fmt.Errorf("load %q: %w", p, err)
			}
			chunks = append(chunks, c...)
		}
	}
	return chunks, nil
}

func ingestJSONArray(loader *DocumentLoader, src map[string]string) ([]DocumentChunk, error) {
	filePath := src["path"]
	arrayField := src["array_field"]
	idPathStr := src["id_path"]

	var idPath []string
	if idPathStr != "" {
		for _, part := range strings.Split(idPathStr, ".") {
			if part != "" {
				idPath = append(idPath, part)
			}
		}
	}

	data, err := os.ReadFile(filePath)
	if err != nil {
		return nil, fmt.Errorf("read %q: %w", filePath, err)
	}
	var root interface{}
	if err := json.Unmarshal(data, &root); err != nil {
		return nil, fmt.Errorf("parse json %q: %w", filePath, err)
	}

	var items []interface{}
	if rootMap, ok := root.(map[string]interface{}); ok {
		if arr, ok := rootMap[arrayField].([]interface{}); ok {
			items = arr
		}
	} else if arr, ok := root.([]interface{}); ok {
		items = arr
	}

	stem := strings.TrimSuffix(filepath.Base(filePath), filepath.Ext(filePath))
	var chunks []DocumentChunk
	for _, item := range items {
		var name interface{} = item
		for _, key := range idPath {
			if m, ok := name.(map[string]interface{}); ok {
				name = m[key]
			} else {
				name = "unknown"
				break
			}
		}
		nameStr := fmt.Sprintf("%v", name)
		if nameStr == "" || nameStr == "<nil>" {
			nameStr = stem
		}
		payload, err := json.Marshal(map[string]interface{}{arrayField: []interface{}{item}})
		if err != nil {
			return nil, fmt.Errorf("marshal item: %w", err)
		}
		c, err := loader.LoadBytes(payload, nameStr, "json")
		if err != nil {
			return nil, fmt.Errorf("load_bytes: %w", err)
		}
		chunks = append(chunks, c...)
	}
	return chunks, nil
}

