        if count < 100:
            try:
                obj = json.loads(line)
                if isinstance(obj, dict):
                    for k, v in obj.items():
                        if k not in key_types:
                            key_types[k] = _python_type_to_str(v)
                count += 1
            except json.JSONDecodeError:
