func (idx *Index) resolveDomains(namespaces, domains []string) []string {
	if namespaces == nil && domains == nil {
		return nil
	}

	var targetNS []string
	if len(namespaces) > 0 {
		targetNS = namespaces
	} else {
		for ns := range idx.domainMap {
			targetNS = append(targetNS, ns)
		}
	}

	var ids []string
	if domains != nil {
		for _, ns := range targetNS {
			nsMap, ok := idx.domainMap[ns]
			if !ok {
				continue
			}
			for _, name := range domains {
				if did, found := nsMap[name]; found {
					ids = append(ids, did)
				}
			}
		}
	} else {
		for _, ns := range targetNS {
			nsMap, ok := idx.domainMap[ns]
			if !ok {
				continue
			}
			for _, did := range nsMap {
				ids = append(ids, did)
			}
		}
	}

	if len(ids) == 0 {
		return nil
	}
	return ids
}
